var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"끄흠… 낭패로구나…","JPN":"ぐう……まさかっ、こんなことに……","ENG":"Agh… This is a disaster…","TWN":"咳… 真糟糕…"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"우리 삼군문이… 뭔지도 모를 저 괴물에게 전부 당하다니… 쿨럭…","JPN":"我々三軍門が……得体の知れないあの化け物にやられるとは……ゴホッ……","ENG":"To think… the entire Trivanguard was wiped out by some monster we don't even recognize… *Cough…*","TWN":"我們三軍門… 竟然被那個不知道是什麼的怪物給全滅了… 咳…"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"침식에 오염된 상처는 여럿 보아왔으나… 이토록 하얀 상처는 처음 보는구려.","JPN":"侵食に汚染された傷は今まで多く見て来たが……こうも白い傷は初めてである。","ENG":"I've seen my fair share of Corruption wounds, but… I've never seen one this pale before.","TWN":"我見過許多被侵蝕污染的傷口… 但像這樣潔白的傷口，我還是第一次見。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…다른 전대와 연락이 닿지 않아.","JPN":"……他の戦隊と連絡ができないわ。","ENG":"…We still can't reach any of the other divisions.","TWN":"…無法聯繫到其他戰隊。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"아무래도 관리국의 상황이 예상보다 나쁜 모양이군.","JPN":"どうやら管理局の状況は予想よりも深刻なようだ。","ENG":"Then it's safe to say the Administration is in worse shape than we thought.","TWN":"看來管理局的狀況比預想的還要糟糕。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"하담, 양상 어른을 부탁해. 내가 의사를 모셔올게.","JPN":"カタン、リョウジさんをお願い。私が医者を呼んでくるわ。","ENG":"Ha Dam, please take care of Elder Yangsang. I'll go find a doctor.","TWN":"夏垣，梁尚叔就拜託你了。我去請醫生。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"아니. 가지 말아라. 너희에게 전할 말이 있다.","JPN":"いや、行くな。お前たちに伝えねばならないことがある。","ENG":"No. Don't go. I've something I need to say to you both.","TWN":"不。別去。我有話要告訴你們。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그런 건 치료를 한 뒤에도 늦지 않습니다.","JPN":"そんなの、治療が終わってからでも遅くありません。","ENG":"That can wait until after we get you treated.","TWN":"這種事治療之後再說也不遲。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"그냥 곁에 있거라. 부질없는 짓으로 내 남은 시간을 허비하고 싶진 않구나.","JPN":"そうせずともよい。余計なことで、私に残された時間を無駄にしたくはない。","ENG":"Just stay by my side. I don’t wish to waste what little time I have left on meaningless things.","TWN":"就待在我身邊吧。我不想浪費我剩下的時間去做無用的事。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"그리 상심한 표정 짓지 말아라. 다시 일어서야 할 것 아니냐?","JPN":"そう落胆するな。再び立ち上がらねばならないんだぞ。","ENG":"Don't look so broken up. You've still got to stand back up, don't you?","TWN":"不要露出這麼悲傷的表情。不是還要重新振作起來嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이런 상황에, 남겨진 저희가 뭘 할 수 있나요?","JPN":"こんな状況で、残された私たちに何ができるというのですか？","ENG":"After all this, what are we even supposed to do?","TWN":"在這種情況下，我們這些剩下的人還能做什麼？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"명달 영감님께선… 나전 천갑이 무너지면 범을 막을 인재는 너희 둘 뿐이라 하셨다.","JPN":"アカタツ殿は……螺鈿天甲が崩れたら、虎を止められる者はお前たち2人だけだと仰った。","ENG":"Old Myeongdal once said… if the Heavenly Inlaid Armor ever fails, only the two of you would be left who could stop the Tiger.","TWN":"明達老頭說過… 如果螺鈿天甲瓦解，能阻止老虎的人就只剩下你們兩個了。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"그러니 우리가 다 죽는 한이 있어도… 너희가 살았다면 의미는 있는 게지.","JPN":"だから、他の皆が散ろうとも……お前たち2人が生きているなら、意味がある。","ENG":"So even if we all fall… if you two survive, that's enough to make it matter.","TWN":"所以就算我們都死了… 只要你們活著，就有意義。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"하담아. 이 늙은이 잔소리 한 번 들어주겠니?","JPN":"カタン。この老いぼれの小言を聞いてくれるか。","ENG":"Ha Dam. Would you indulge this old man one last rant?","TWN":"夏垣。你能聽我這個阿姨再嘮叨一次嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"…경청하오리다. 양상 어른.","JPN":"……ああ、リョウジ殿。","ENG":"…I'm listening, sir.","TWN":"…我會洗耳恭聽的，梁尚叔。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"네가 했던 말처럼… 가족을 꾸리고 지킨다는 일은 결코 쉽지 않을 거다.","JPN":"お前が言った通り……家庭を作り守り抜くことは決して容易いことではない。","ENG":"Just like you said… building a family and keeping it together won't be easy.","TWN":"就像你說的那樣… 組織家庭、守護家庭絕非易事。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"허나 도공이 힘들게 빚은 도자기는 그만큼 아름다울 것이요. 또한 언제 깨질지 모르는 그런 연약한 것이기에…","JPN":"しかし、職人が丹精込めて作った陶磁器はその分美しいものであり、また、いつ割れるか分からない脆いものだからこそ……","ENG":"But a potter's jar, shaped with care and effort, holds beauty. Fragile as it may be, never knowing when it'll crack…","TWN":"但是，陶工辛勤製作的瓷器，因此而美麗。又因為那是隨時可能破碎的脆弱之物…"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"…그만큼 간절한 마음으로 빚어내는 것이라 생각한다.","JPN":"……それだけ切実な想いを込めて作るのだろう。","ENG":"…I believe that's why it's made with such longing in the first place.","TWN":"…所以我認為，他們會懷著那樣迫切的心情去製作。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"깨어질까 두려워 지레 겁먹지 말거라.","JPN":"壊れることを恐れて怯えるな。","ENG":"Don't fear breakage before it happens.","TWN":"不要因為害怕破碎而退縮。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"내일의 상실을 염려하여 오늘의 기꺼움을 피하지 말아라.","JPN":"来るかもわからない喪失を憂いて、今日の喜びから逃げるな。","ENG":"Don't avoid today's joy because of tomorrow's grief.","TWN":"不要因為擔心明日的失去，而迴避今日的喜悅。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"이것이…","JPN":"これが……","ENG":"This is…","TWN":"這就是…"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MEMBER3_NPC_SAMGUN_NULL","text":{"KOREA":"너희에게 남기는 내 마지막 잔소리다…","JPN":"私からの、最後の小言だ……","ENG":"The last piece of advice I'll ever give you…","TWN":"我留給你們最後的嘮叨…"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"…명심하리다.","JPN":"……肝に命じておこう。","ENG":"…I'll take it to heart.","TWN":"…我會銘記在心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"양상은 양지 바른 곳에 묻었느냐?","JPN":"リョウジはいい場所に埋めてやったか。","ENG":"Did you lay Yangsang to rest in a sunny spot?","TWN":"梁尚，你把他葬在向陽的地方了嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"바라시던대로, 감나무를 머리맡에 두고 잠드시게 해드렸소.","JPN":"本人の望み通り、柿の木を枕にして眠るようにして差し上げた。","ENG":"Just like he asked. Buried him with a persimmon tree at his head.","TWN":"正如他所願，讓他在柿子樹旁長眠了。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그래. 그거면 됐다.","JPN":"ああ、それでいい。","ENG":"Good. That's enough.","TWN":"好。那就好。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"나전 천갑이 깨어졌으니, 머잖아 범이 옛적으로부터 올라올 게다.","JPN":"螺鈿天甲が崩れたなら近いうちに虎が過去よりやってくるだろう。","ENG":"With the Heavenly Inlaid Armor broken, the Tiger will soon rise again from the olden past.","TWN":"螺鈿天甲已經破碎，老虎很快就會從過去爬出來。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"예정대로 우물을 가동할 것이니, 다들 준비하거라.","JPN":"予定通りイドを稼働する。皆準備しておけ。","ENG":"We'll activate the Well as planned. Get everything ready.","TWN":"我們將按計畫啟動井，大家準備好。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"제 불찰로… 삼군문의 식구들을 한순간에 전부 잃었어요.","JPN":"私の不注意で……三軍門の仲間を一瞬で失ってしまいました。","ENG":"Because of my mistake… I lost the entire Trivanguard in an instant.","TWN":"都是我的疏忽… 讓三軍門的家人在一瞬間全部失去了。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"세상을 뒤덮은 풍랑을 어찌 사람의 탓이라 하겠느냐?","JPN":"風浪が世を襲っても、それは人のせいではないのだ。","ENG":"You can't blame people for a storm that swallows the world.","TWN":"席捲世界的風浪，怎能歸咎於個人？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"명달 대장은 침착하시네요.","JPN":"隊長は落ち着いていますね。","ENG":"You're so calm, Commander.","TWN":"明達隊長你真是冷靜。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그 점괘라는 것 때문인가요?","JPN":"その占いのおかげですか？","ENG":"Is it because of that fortunetelling?","TWN":"是因為那個卜卦嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"전부 알고 있으면서도… 말을 아끼신 거에요?","JPN":"全部分かっていながら……わざと教えてくれなかったのですか？","ENG":"You knew… but you said nothing?","TWN":"你明明知道一切… 卻沒有說出口？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"나는 남들의 수십 갑절이 되는 삶을 살았다.","JPN":"俺は人の数十倍も生きてきた。","ENG":"I've lived a life ten times longer than most.","TWN":"我比你們多活了幾十倍的人生。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"운명을 바꾸겠다며 길길이 날뛰던 시절의 햇수가 너희가 살아온 날보다 많지.","JPN":"運命を変えてやると怒り狂い、暴れていた年月こそ、お前たちが生きてきた時間よりも長い。","ENG":"Spent more years fighting fate than either of you have even been alive.","TWN":"我為了改變命運而瘋狂的日子，比你們活著的時間還要多。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그 애달픔과 무력함을 하소연하는 것조차, 지나고 돌아오지 않을 바람이란 걸 깨달을 무렵엔…","JPN":"その悲しみや無力さを訴えることすらも、決して敵わない願いだと気づいた頃には……","ENG":"By the time I realized grief and helplessness are winds that never blow back…","TWN":"當我意識到，就連抱怨那份悲痛和無力感，都像是過去的風一樣無法回來時…"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"더 이상 운명을 바꾸겠다는 어리석은 말은 입 밖에 내지 않게 되었다.","JPN":"運命を変えるなどという愚かな言葉は口にしなくなった。","ENG":"I'd stopped saying foolish things like changing fate.","TWN":"我就再也不會說出改變命運這種愚蠢的話了。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그럼에도… 모든 것을 잃어버린 상실과 지키지 못한 부끄러움은… 좀처럼 익숙해지지 않는구나.","JPN":"それでも……すべてを失った喪失感と、守れなかった恥ずかしさは……なかなか慣れないものだな。","ENG":"But still… the shame of failing to protect, the ache of losing it all… you never get used to that.","TWN":"即便如此… 失去一切的失落感和無法守護的羞愧… 卻始終無法習慣。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"두 사람은 삼군문을 떠나라.","JPN":"2人とも三軍門を去るんだ。","ENG":"The two of you should leave the Trivanguard behind.","TWN":"你們兩個離開三軍門吧。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"너희의 운명을 바꾸고 싶다면 기회는 지금 뿐이다.","JPN":"お前たちの運命を変えたいなら、チャンスは今しかない。","ENG":"If you want a different future, this is your only chance.","TWN":"如果想改變自己的命運，機會就只有現在。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"저희가 떠나면 범은 누가 막나요?","JPN":"私たちがいなくなったら、虎は誰が止めるのですか？","ENG":"And if we do, who's going to stop the Tiger?","TWN":"如果我們離開，誰來阻止老虎呢？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"내가 말하지 않았느냐? 중요한 순간을 위해 힘을 아껴두었다고.","JPN":"何度も言っただろう？　肝心な時のために力を温存しておいたと。","ENG":"Didn't I say? I've been saving my strength for the one moment that counts.","TWN":"我不是說過嗎？我為重要的時刻儲備了力量。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"나 혼자의 힘으로 놈을 잡을 수만 있다면 그것이 최고일 테지만…","JPN":"俺一人の力でやつを倒すことができるなら、それが一番だが……","ENG":"If I can take it down myself, then that's best…","TWN":"如果我能靠自己的力量抓住那傢伙，那當然最好…"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"호랑이 뱃속에 들어가도 정신만 차리면 10년은 버티는 법이다.","JPN":"虎に食われても、気をしっかり保てば10年は行けるだろう。","ENG":"But even if I end up in its belly, so long as I keep my wits, I'll hold out for ten years.","TWN":"俗話說，就算進了老虎肚子裡，只要保持清醒，也能撐十年。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그럼 그 10년 뒤는 어찌 되는 건데요!","JPN":"じゃあ、10年後はどうなるんですか！","ENG":"And what happens after ten years?!","TWN":"那十年後又會怎麼樣呢！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"삼군문의 대장이 살아야 10년 뒤에도 기약이 있을 것 아닙니까!","JPN":"アカタツ隊長が生きていてこそ、見据えられる10年ではありませんか！","ENG":"Trivanguard's commander have to live for there to be a ten years later!","TWN":"只有三軍門的隊長活著，十年後才會有希望不是嗎！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"자고로 운명이란, 엎어지고 뒤치락하여도 결국은 흘러야 할 곳으로 돌아가는 법.","JPN":"運命とは、あちこちに寄り道をしても最後は向かうべき方向へ向かうもの。","ENG":"Fate may stumble and twist, but it always flows back where it's meant to.","TWN":"自古以來，命運即便跌宕起伏，最終也會回到它該流向的地方。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그런 쓸데없는 걱정일랑 말고 앞으로 너희 10년을 어떻게 꾸려갈 지나 고민하거라.","JPN":"余計な心配はせず、これからの10年どう生きるかを考えろ。","ENG":"Forget worrying over me. You should be thinking about how to shape your own next ten years.","TWN":"別再為那種無聊的事擔心了，好好想想你們未來的十年要怎麼過。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"삼군문 대장의 마지막 명령이다.","JPN":"三軍門隊長としての最後の命令だ。","ENG":"That's the final order of the Trivanguard's commander.","TWN":"這是三軍門隊長最後的命令。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"하담아. 우물을 가동해다오.","JPN":"カタン、イドを稼働してくれ。","ENG":"Ha Dam. Activate the Well.","TWN":"夏垣。啟動井吧。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"…알겠소.","JPN":"……承知した。","ENG":"…Understood.","TWN":"…明白了。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"제일삼검이 세 짐승의 목을 베니, 그 피가 대지를 적시어 사람에게 저주를 내렸다.","JPN":"三剣極が3匹のケモノの首を斬ると、その血が大地を濡らし、人々に呪いをかけた。","ENG":"The Three Blades struck down the Three Beasts and their blood soaked the land, cursing mankind in its wake.","TWN":"第一劍客斬斷了三隻野獸的頭顱，其血浸濕大地，給人類帶來了詛咒。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"세 짐승의 저주는 곧 땅내림이라는 세 가지 화를 불러들이니…","JPN":"そして3匹のケモノの呪いはチガカリという3つの災いをもたらした。","ENG":"From their curses came the three scourges called the Earthbound…","TWN":"三隻野獸的詛咒，帶來了名為地脈之力的三種禍患…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"하나는 늙지 못하는 저주요. 다른 하나는 같은 삶을 되풀이하는 저주이며, 나머지는 대물림의 저주라.","JPN":"1つ目は老いることのできない呪い。2つ目は同じ生を繰り返す呪い。最後は受け継ぐ呪いだ。","ENG":"One, the curse of never growing old. Another, the curse of repeating the same life. And the last, the curse of inheritance.","TWN":"一是無法變老的詛咒。另一種是重複相同人生的詛咒，剩下的是傳承的詛咒。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"셋에 닮은 꼴이 있다면 그 끝에 한을 품고 마는 팔자를 타고남이렸다.","JPN":"3つの呪いの共通点は、最後に未練を抱いてしまう運命の下に生まれること。","ENG":"What all three shared was a fate steeped in sorrow, destined to end in lingering regret.","TWN":"如果說三者有什麼共同點，那就是他們都生來就註定會懷抱遺憾。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"그 중에도 유달리 기구하기 짝이 없는 팔자의 남녀 한 쌍이 있으니.","JPN":"中でもある一組の男女は、悲運の極みと言える運命を背負うことになる。","ENG":"Among them was a pair bound by a fate crueler than most.","TWN":"其中，有一對男女的命運尤其坎坷。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"그것은 연인을 잃는 삶을 되풀이하는 남자와, 그런 남자를 사랑해버리고 마는 삶을 대물림하는 여자요.","JPN":"恋人を失う生を繰り返す男と、その男を愛してしまう生を受け継ぐ女。","ENG":"The man, cursed to relive a life where he always loses his beloved. The woman, bound to inherit the life of loving that very man.","TWN":"那是個重複著失去戀人的人生輪迴的男人，以及一個傳承著愛上那個男人的詛咒的女人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"늙지 못하는 이는 평생토록 그 한 쌍을 가엽게 여겨 팔자를 고쳐주고자 하나, 영영 그 바람을 이루지 못할 팔자일세.","JPN":"老いない者は一生その2人を哀れみ、運命を変えようとするが、永遠にその願いは叶わない運命にあった。","ENG":"The one who cannot grow old has pitied that pair for a lifetime, wishing only to rewrite their fate. But alas, even that wish was a fate never meant to be fulfilled.","TWN":"無法變老的人一輩子都憐憫著那對男女，想改變他們的命運，但卻永遠無法實現這個願望。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그 팔자의 흐름이 거스르지 못할 폭포인 줄 알았더라면… 차라리 체념하고 흘러가는 대로 살았을까?","JPN":"運命の流れが逆らえない滝のようなものだと分かっていれば……いっそのこと、諦めて流れに身を任せ生きられたのだろうか。","ENG":"If I had truly known that fate flowed like a waterfall that couldn't be defied… would I have just given in and gone with it?","TWN":"如果早知道命運的洪流是無法逆轉的瀑布… 我會選擇認命，隨波逐流嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"아니면 거스르지 못할 것을 거스르려는 발버둥조차도… 우리의 타고난 팔자인 것일까?","JPN":"それとも、逆らえないものに逆らおうと足掻くこともまた……俺たちの運命なのだろうか。","ENG":"Or maybe even that futile struggle… is part of our fate too.","TWN":"還是說，連試圖逆轉無法逆轉之物的掙扎… 也是我們天生的命運？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"옆에 말벗이 있는데, 어찌 혼잣말만 중얼거리시나요.","JPN":"隣に話し相手がいるのに、なぜ独り言ばかり言っているのですか。","ENG":"You've got someone to talk to, you know. Why are you muttering to yourself?","TWN":"旁邊有個人可以說話，為什麼只自言自語？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"너…?","JPN":"お前……？","ENG":"You…?","TWN":"你…？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"이 노인의 충고를 귀담아듣지 않고, 기어이 따라올 셈이냐?","JPN":"俺の忠告を無視して、どうしてもついて来るつもりか？","ENG":"Even after I told you to leave, you still followed me?","TWN":"你不聽這個老人的忠告，執意要跟來嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"운명을 바꾸고 싶으면 삼군문을 떠나라고 하셨죠.","JPN":"運命を変えたいなら三軍門を去れと言いましたね。","ENG":"You said if I wanted to change my fate, I had to walk away from the Trivanguard.","TWN":"你說過，想改變命運就離開三軍門。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"세상을 지키라고 모인 사람이 대장을 사지로 내몰고 도망치는 게 운명을 거스르는 길이라면…","JPN":"世界を守るため集ったのに、隊長を死地へ追いやって逃げなければ運命に逆らえないというのなら……","ENG":"But if leaving you behind to die is what counts as defying fate…","TWN":"如果說，身為守護世界之人，卻將隊長推向死地並逃跑，是改變命運的方法…"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"차라리 흐름에 몸을 맡기고 가렵니다.","JPN":"私は流れに身を任せる道を選びます。","ENG":"I'd rather let it carry me wherever it will.","TWN":"那我寧願順著這股洪流走。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그 흐름의 끝에 연옥이 있다고 해도 말이냐?","JPN":"その先に煉獄が待っているとしてもか？","ENG":"Even if that current ends in purgatory?","TWN":"即使這股洪流的盡頭是煉獄？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"누가 죽으러 가나요? 세상을 지키러 가는 건데.","JPN":"何も、死ぬために行くんじゃありません。世界を守るために行くんです。","ENG":"Who's dying? We're going to save the world.","TWN":"誰說要去送死？我們是要去守護世界。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"범이 머무는 <color=#ffd34c>옛적</color>에 이르려면 아직 내려갈 길이 멀다.","JPN":"虎が留まる<color=#ffd34c>過去</color>に辿り着くまでの道のりは長い。","ENG":"We've still got a long way down if we're to reach the Tiger in <color=#ffd34c>the past</color>.","TWN":"要到達老虎停留的<color=#ffd34c>過去</color>，還有很長一段路要走。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그동안 잘 생각해보아라. 언제든 돌아가도 상관없으니.","JPN":"その間よく考えてみろ。いつ引き返しても構わない。","ENG":"Think carefully while you can. You're free to turn back anytime.","TWN":"這段時間你好好想想吧。隨時都可以回去。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"네, 갑자기 마음이 바뀌면 혼자서라도 도망칠게요.","JPN":"はい、途中気が変わったら一人でも逃げ出します。","ENG":"Sure. If I suddenly change my mind, I'll run off by myself.","TWN":"好，如果我突然改變心意，我會自己逃跑的。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"하담이는 혼자 남겨두고 온 거냐?","JPN":"カタンを残して来たのか。","ENG":"You left Ha Dam behind?","TWN":"你把夏垣一個人留在那邊嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"우리가 범이 있는 곳까지 내려갈 수 있도록 우물을 조작할 사람은 필요하니까요.","JPN":"私たちが虎のいる所までに下りて行けるように、イドを操作してくれる人が必要ですからね。","ENG":"Someone had to stay up there to operate the Well.","TWN":"因為需要有人操控井，才能讓我們抵達老虎所在的地方。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그리고 동앗줄이란 것도 곧 내려 보내준다네요.","JPN":"あと、もうすぐ縄というものを下してくれるそうですよ。","ENG":"And he said he'd send down the Tether soon.","TWN":"而且他說很快就會把繩索放下來。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"동앗줄? 그새 또 뭔가를 만들어낸 건가?","JPN":"縄？　また何かを作ったのか。","ENG":"The Tether? What's he made now?","TWN":"繩索？這麼快又做了什麼東西？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"우물의 안과 밖을 이어주는 밧줄이래요.","JPN":"イドの内と外とを繋ぐものだそうです。","ENG":"He said it's a rope connecting the inside and outside of the Well.","TWN":"他說是連接井內和井外的繩子。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"안쪽이 위험에 처하면 바깥으로 끌어올릴 수 있고, 바깥에서 그걸 타고 안으로 올 수도 있다던데요?","JPN":"中の人が危険な状態になったら外に引き上げることができて、逆にそれを使って外から中に入ることもできるんだとか。","ENG":"If things go bad inside, it can pull us out. Or if needed, let someone come in from above.","TWN":"如果井內遇到危險，可以拉上來，也可以從外面順著它進去。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"거… 준비성 한 번 철저한 놈이구나.","JPN":"本当に……準備のいいやつだ。","ENG":"Hmph… That guy's always prepared for everything.","TWN":"這… 準備得真周全。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"후후, 그렇죠?","JPN":"ふふ、でしょう？","ENG":"Haha, right?","TWN":"呵呵，是吧？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"서생처럼 똑똑하고 듬직한 사람을 만난 건, 평생에 다신 없을 축복이라고 생각해요.","JPN":"ショウのように頭がよくて頼もしい人に出会えたのは、生涯で二度とない祝福だと思います。","ENG":"Meeting someone as brilliant and reliable as Seosaeng was a once-in-a-lifetime kind of blessing.","TWN":"我認為能遇到像書生這樣聰明又可靠的人，是人生中再也得不到的祝福。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"저희의 만남이 우연이 아니라 운명이란 얘길 처음 들었을 땐, 살짝 소름이 돋았지만요.","JPN":"私たちの出会いが偶然ではなく運命だと初めて聞かされた時は、少し鳥肌が立ちましたけどね。","ENG":"I got goosebumps the first time I heard our meeting was fate.","TWN":"當我第一次聽到我們之間的相遇不是偶然而是命運時，我有點毛骨悚然。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그런데, 삼군문의 피를 타고난 삶은 축복이 아니라 저주잖아요.","JPN":"ところで、三軍門の血を受け継いだ人間の生は呪われているじゃないですか。","ENG":"But being born with Trivanguard blood is not a blessing but a curse.","TWN":"但是，繼承了三軍門之血的人生，不是祝福而是詛咒。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"저희 두 사람의 인연도… 결국 좋게 끝나진 않는 거죠?","JPN":"では私たち2人の因縁も……いい終わり方をしないんでしょうね。","ENG":"So maybe the two of us… won't have a happy ending either?","TWN":"我們兩個的緣分… 最終也不會有好結果吧？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"내 점괘는 듣고 싶지 않다더니. 이제 와서 마음이 바뀐 게냐?","JPN":"俺の占いは聞きたくないと言ったくせに。ここに来て気が変わったか？","ENG":"Didn't want to hear your fortune back then. Changed your mind now?","TWN":"你說過不想聽我的卜卦。現在又改變心意了？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"오늘 하루, 참 많은 일을 겪었잖아요.","JPN":"今日一日、色んな事がありました。","ENG":"It's been a long day, don't you think?","TWN":"我們今天一天，經歷了這麼多事。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"꽃 필 무렵의 인생이 찰나에 꺾여 나가듯, 사람 마음이란 것도 갈대처럼 꺾이나 봐요.","JPN":"花盛りの人生が一瞬で壊されたように、人の心というのも脆くすぐ折れるみたいです。","ENG":"Life's like a flower in bloom, gone in a blink. Hearts bend like reeds.","TWN":"人生就像花季在瞬間凋零一樣，人心也像蘆葦一樣會被折斷。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"평생 행복할 궁리만 하며 살았는데…","JPN":"一生、幸せになることしか考えていなかったのに……","ENG":"I've spent my life planning for happiness…","TWN":"我一輩子只想著如何幸福地生活…"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이젠 안 좋은 일도 준비가 필요할 것 같아서요.","JPN":"これからは、悪いことにも備えないといけないんだなーと思ったんです。","ENG":"But maybe I need to start preparing for sorrow too.","TWN":"現在覺得，好像也需要為不好的事情做準備了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"유달리 기구하기 짝이 없는 팔자를 타고난 남녀 한 쌍이 있다네.","JPN":"ある一組の男女は、悲運の極みと言える運命を背負うことになる。","ENG":"There exists a pair bound by a fate crueler than most.","TWN":"有一對命運尤其坎坷的男女。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"남자는 가장 사랑한 사람을 잃는 생애를 되풀이하는 윤회에 갇혔고.","JPN":"男は繰り返される生の度に、最も愛する人を失うという輪廻に閉じ込められ……","ENG":"The man is trapped in a cycle of rebirth, doomed to lose the one he loves most in every life.","TWN":"男人被困在重複失去最愛之人的輪迴中。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"여자는 그런 남자를 사랑해버리고 마는 삶을 대물림으로 이어받았지.","JPN":"女はそんな男を愛してしまう生を受け継ぐ運命に生まれた。","ENG":"And the woman has inherited a life in which she cannot help but fall for that very man.","TWN":"女人則繼承了愛上那個男人的命運。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"차라리 처음부터 연이 아니었더라면 좋으련만…","JPN":"最初から縁がなければよかったものを……","ENG":"If only had they never been fated to meet in the first place…","TWN":"如果從一開始就沒有緣分就好了…"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"그들은 어찌하여 그 기구한 운명을 잊은 채, 매 생애 애달픈 사랑을 품고 마는 것인가.","JPN":"なにゆえ彼らは、こうも悲しき運命を幾度も忘れ、こうも切なき愛を幾度もしてしまうのか。","ENG":"Yet, why is it that they forget this cruel fate each time, only to fall once more into a sorrowful love with every new life?","TWN":"他們為何會忘記這坎坷的命運，在每一次生命中都陷入悲傷的愛情呢。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"서생.","JPN":"ショウ。","ENG":"Seosaeng.","TWN":"書生。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L46_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"우물 아래에서 보내는 이 메시지가 닿을진 모르겠지만…","JPN":"イドの下から送るメッセージがあなたに届くかは分からないけど……","ENG":"I don't know if this message will reach you from down in the Well…","TWN":"這條來自井底的訊息，我不知道你能不能收到…"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신에게 꼭 하고 싶은 말이 있어.","JPN":"あなたに伝えたいことがあるの。","ENG":"But there's something I need to tell you.","TWN":"但我有一句話一定要告訴你。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"만약 내가 당신을 잃게 된다면 말이야.","JPN":"もし私があなたを失ってしまったら。","ENG":"If I ever lose you…","TWN":"如果，我失去了你。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"난 평생을 회한에 잠긴 채로 남은 여생을 살아갈 거야.","JPN":"私は後悔に満ちたまま、残りの人生を生きるわ。","ENG":"I'll spend the rest of my life drowning in regret.","TWN":"我會一輩子活在悔恨之中。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신도, 나도 그런 미래를 바란 적은 없겠지만… 인생이란 건 원래 뜻대로 안 되는 거잖아.","JPN":"あなたも私も、そんな未来は望んでないけど……人生って思い通りにいかないものでしょう。","ENG":"Neither of us wanted that future… but life doesn't care what we want, does it?","TWN":"你和我都不想要那樣的未來，但人生本來就不會事事如意。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그러니 이것 하나만 약속해줘.","JPN":"だからこれだけは約束してちょうだい。","ENG":"So just promise me this.","TWN":"所以請你答應我一件事。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"언젠가, 우리 둘 중 한 사람만 남게 된다면…","JPN":"いつか、あなたと私のどちらかが一人残されることになったら……","ENG":"If either of us ends up alone…","TWN":"總有一天，如果我們兩人中只剩下一個…"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"남은 사람은 이곳에서 있었던 모든 기억을 지우고 관리국을 떠나, 자유롭게 살아가기로.","JPN":"残された人はここでの記憶をすべて消して管理局を去り、自由に生きるのよ。","ENG":"The one left behind will erase every memory of this place and walk away from the Administration. To live free.","TWN":"剩下的人，要將這裡發生的一切記憶全部抹去，離開管理局，自由地生活。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그럼… 다음에 다시 만나자.","JPN":"じゃあ……また会いましょう。","ENG":"So… until next time.","TWN":"那麼… 後會有期。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그때까지 안녕.","JPN":"その時まで、さようなら。","ENG":"Goodbye.","TWN":"再見。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L10_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"조금만 더 내려가면, 과거를 오르는 범과 마주하게 되겠군.","JPN":"もう少し下りて行けば、過去を遡る虎と遭遇するだろう。","ENG":"Just a bit further down, and we’ll come face to face with the Tiger climbing up from the past.","TWN":"很快就要到底了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그러게요. 이렇게 깊이 거슬러 내려온 건 처음인데, 별 탈 없이 도착했어요.","JPN":"そうですね。こんなに深く時間を下ったのは初めてですが、無事辿り着きました。","ENG":"Right. I've never come this far down before, but we made it without any trouble.","TWN":"是啊。這麼深的地方我還是第一次下來，但比想像中順利。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"명달 대장이 삼군문의 머리에 서생 같은 똑똑한 길잡이를 둔 덕이겠죠.","JPN":"三軍門の参謀の座に、ショウのような賢い道案内役を配置したアカタツ隊長のおかげでしょう。","ENG":"Must be thanks to Commander Myeongdal having a clever guide like Seosaeng at the helm of Trivanguard.","TWN":"這都是因為明達隊長為三軍門留下了一個聰明的嚮導。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…연화야.","JPN":"……レンカ。","ENG":"…Yeonhwa.","TWN":"…蓮華。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Yes?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"아직 늦지 않았으니, 지금이라도 돌아가거라.","JPN":"まだ間に合う。今からでも帰れ。","ENG":"It's not too late. You can still turn back now.","TWN":"還不晚，你現在回去吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"이 아래엔 영광도 미래도 없다.","JPN":"この下には栄光も未来もない。","ENG":"There's no glory or future waiting down there.","TWN":"這裡沒有榮耀，也沒有未來。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"범은 연옥에 떨어지는 한이 있어도 모든 걸 게걸스럽게 삼킨 채 추락하고 다시금 깨어날 테니.","JPN":"虎は煉獄に堕ちようともすべてを貪りつくして墜落し、いずれ再び目を覚ます。","ENG":"Even if it means falling into purgatory, the Tiger will devour everything, fall, and rise again.","TWN":"老虎即便墜入煉獄，也會貪婪地吞噬一切，然後墜落。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"음…","JPN":"うーん……","ENG":"Hmm…","TWN":"嗯…"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"대장 마음은 알겠는데 별로 안 무섭네요.","JPN":"隊長の気持ちは分かりますけど、全然怖くありませんね。","ENG":"I get that you're worried, but I'm not scared.","TWN":"我明白隊長的心意，但我一點也不害怕。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"절 겁주려면 도깨비 탈 정도는 쓰고 놀래키셨어야죠.","JPN":"私を怖気付かせたいなら、鬼の面を被って脅すぐらいはしないと。","ENG":"If you really wanted to scare me, you should've worn a demon mask or something.","TWN":"如果你想嚇我，至少要戴個鬼面具才行。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"이제 막 재능을 꽃 피우기 시작한 네가 희생을 입에 담기엔 아직 이르단 것을 어찌 모르느냐?","JPN":"才能を開花させたばかりのお前が、犠牲を口にするのはまだ早すぎる。どうしてそれがわからないのだ。","ENG":"Don't you realize it's too early for someone just beginning to blossom to be talking about sacrifice?","TWN":"你才剛開始展露才華，怎麼能把犧牲掛在嘴邊？難道你不知道嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"아직 그 점괘를 마음에 담아두고 있는 거라면…","JPN":"あの占いをまだ気に留めているのなら……","ENG":"If you're still clinging to that old fortune…","TWN":"如果你還把那個卜卦放在心上…"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"처음 저를 삼군문으로 데려올 때 말씀하셨잖아요. 범을 잡으려면 제가 필요하다고.","JPN":"私を三軍門に連れてきたときに仰ったでしょう。虎を倒すためには私が必要なのだと。","ENG":"You said it yourself when you brought me into Trivanguard. That I was needed to catch the Tiger.","TWN":"當初你把我帶到三軍門時不是說過嗎？要抓住老虎，就需要我。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이제 와서 저만 빼놓고 혼자 갈 생각일랑 마셔요.","JPN":"今更私を帰して一人で行くなんてなしです。","ENG":"So don't even think about leaving me behind now.","TWN":"現在想把我撇下，一個人去嗎？別想了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"서생이 곧 기슭으로 내려가는 동앗줄을 내려줄 게다. 잠시 숨 돌릴 틈은 있겠지.","JPN":"もうすぐショウが麓へ降りるための縄を下ろしてくれるだろう。一息つく暇はあるはずだ。","ENG":"Seosaeng will soon lower the rope down to the next ridge. You should have a moment to catch your breath.","TWN":"書生很快就會放下通往山腳的繩索。我們能稍微喘口氣。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"아, 그러고보니 좀 전에 봐 둔 개울이 있는데…","JPN":"あ、そういえばさっき小川を見つけたので……","ENG":"Ah, come to think of it, I saw a stream earlier…","TWN":"啊，對了，我剛才看到一條小溪…"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이 참에 세수나 좀 하고 와야겠…","JPN":"今の内に顔を洗って……","ENG":"I'm going to go wash my face–","TWN":"趁現在去洗把臉吧…"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"떠나기 전에.","JPN":"その前に。","ENG":"Before you go.","TWN":"在離開之前。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"잠시 얘기나 나눠보는 게 어떻겠소.","JPN":"少し話をしないか。","ENG":"Would you spare a moment to talk?","TWN":"我們聊一聊如何。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"서생…?","JPN":"ショウ……？","ENG":"Seosaeng…?","TWN":"書生…？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};